#include <stdio.h>
#include <math.h>

long long gcd(long long a, long long b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

long long lcm(long long a, long long b) {
    return (a * b) / gcd(a, b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int A, B;
        scanf("%d %d", &A, &B);
        long long sum = 0;
        for (int a = 1; a <= A; a++) {
            for (int b = 1; b <= B; b++) {
                int n = 2;
                int flag = 1;
                while (n * n <= a && n * n <= b) {
                    if (a % (n * n) == 0 && b % (n * n) == 0) {
                        flag = 0;
                        break;
                    }
                    n++;
                }
                if(flag) sum += lcm(a, b);
            }
        }
        printf("%lld\n", sum % (1LL << 30));
    }
    return 0;
}

